import redis
from redis import StrictRedis

# Set up a Redis client using the redis-py library
redis_client = StrictRedis(host='localhost', port=6379, db=0)

# Prevent unencrypted connections to Redis
redis_client.ssl(True)

# Store sensitive user data in Redis with appropriate TTL values
user_data = {'session_token': '123456', 'api_key': 'abcdef'}
